Here is a simple C++ function that takes a reference to a `std::string` containing markdown formatted text and returns a `std::string` containing HTML formatted text. This function uses the `std::regex` and `std::string` libraries to replace markdown syntax with HTML syntax.

```cpp
#include <regex>
#include <string>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::regex regexHeadings("^# (.*)$", std::regex::ECMAScript);
    std::regex regexBold("^(\\*|__)([^\\*]+)\\1$", std::regex::ECMAScript);
    std::regex regexItalic("^(\\*|_)([^\\*]+)\\1$", std::regex::ECMAScript);
    std::regex regexLinks("\\[(.*)\\]\\((.*)\\)", std::regex::ECMAScript);
    std::regex regexImages("\\!(.*)\\((.*)\\)", std::regex::ECMAScript);
    std::regex regexLists("^\\s*([\\*+-])\\s(.*)$", std::regex::ECMAScript);

    std::smatch match;

    // Headings
    while (std::regex_search(markdown, match, regexHeadings)) {
        html += "<h" + std::to_string(match.size() - 1) + ">" + match[1] + "</h" + std::to_string(match.size() - 1) + ">\n";
        markdown = match.suffix().str;
    }

    // Bold
    while (std::regex_search(markdown, match, regexBold)) {
        html += "<b>" + match[2] + "</b>\n";
        markdown = match.suffix().str;
    }

    // Italic
    while (std::regex_search(markdown, match, regexItalic)) {
        html += "<i>" + match[2] + "</i>\n";
        markdown = match.suffix().str;
    }

    // Links
    while (std::regex_search(markdown, match, regexLinks)) {
        html += "<a href=\"" + match[2] + "\">" + match[1] + "</a>\n";
        markdown = match.suffix().str;
    }

    // Images
    while (std::regex_search(markdown, match, regexImages)) {
        html += "<img src=\"" + match[2] + "\" alt=\"" + match[1] + "\">\n";
        markdown = match.suffix().str;
    }

    // Lists
    while (std::regex_search(markdown, match, regexLists)) {
        html += "<ul>\n";
        while (std::regex_search(match[2].str, match, regexLists)) {
            html += "<li>" + match[2] + "</li>\n";
            match.suffix().str = match[2].str;
        }
        html += "</ul>\n";
        markdown = match.suffix().str;
    }

    // Text
    if (!markdown.empty()) {
        html += markdown;
    }

    return html;
}
```

This function supports the following markdown syntax:

- Headings: `# Heading`, `## Heading`, `### Heading`, etc.
- Bold: `**Bold text**`, `__Bold text__`
- Italic: `*Italic text*`, `_Italic text_`
- Links: `[Link text](http://www.example.com)`
- Images: `![Image alt text](http://www.example.com/image.jpg)`
- Lists: `- Item 1`, `+ Item 1`, `* Item 1`

Note that this is a basic implementation and may not support all markdown syntax.

